//! Sovereign AAC-LC (MPEG-4 Audio Object Type 2) audio encoder — pure Rust.
//!
//! `std`+`alloc` only. No external crates, no threads. wasm32-safe.
//!
//! This is the minimal *conformant* AAC-LC subset: long blocks only
//! (1024-sample frames, ONLY_LONG_SEQUENCE), sine window, 50% overlap MDCT,
//! standard long-window scalefactor-band tables, the AAC `^(4/3)` non-linear
//! quantizer, and the AAC spectral Huffman codebooks (we implement the
//! signed codebooks 1..=4, the unsigned codebooks 5..=10, and the escape
//! codebook 11, plus codebook 0 = ZERO_HCB). No short blocks, no TNS, no PNS,
//! no prediction, no intensity/MS stereo (CPE codes both channels independently
//! with common_window=0).
//!
//! The output is a sequence of raw AAC access units (`frames`), the
//! AudioSpecificConfig (`asc`), and a helper [`adts_wrap`] that wraps a raw
//! frame in a 7-byte ADTS header so the frames form a decodable `.aac` stream.
//!
//! Decode verification: see the `#[cfg(test)]` block which climbs the
//! silence -> sine -> stereo/48k ladder against the system `ffmpeg`/`ffprobe`
//! (gate-skipped when absent).

extern crate alloc;
use alloc::vec::Vec;

// ---------------------------------------------------------------------------
// Bit writer (MSB-first), mirroring the H.264 bitstream convention.
// ---------------------------------------------------------------------------

/// MSB-first bit writer with byte accumulation.
pub struct BitWriter {
    bytes: Vec<u8>,
    cur: u8,
    nbits: u32,
}

impl BitWriter {
    pub fn new() -> Self {
        BitWriter { bytes: Vec::new(), cur: 0, nbits: 0 }
    }

    #[inline]
    pub fn put_bit(&mut self, b: u32) {
        self.cur = (self.cur << 1) | ((b & 1) as u8);
        self.nbits += 1;
        if self.nbits == 8 {
            self.bytes.push(self.cur);
            self.cur = 0;
            self.nbits = 0;
        }
    }

    #[inline]
    pub fn put_bits(&mut self, val: u32, n: u32) {
        debug_assert!(n <= 32);
        let mut i = n;
        while i > 0 {
            i -= 1;
            self.put_bit((val >> i) & 1);
        }
    }

    /// Write `n` bits from a wider value (for >32-bit Huffman words we never need this,
    /// but escape sequences can produce up to ~30 bits which fits u32).
    pub fn bit_pos(&self) -> usize {
        self.bytes.len() * 8 + self.nbits as usize
    }

    pub fn align_to_byte(&mut self) {
        while self.nbits != 0 {
            self.put_bit(0);
        }
    }

    pub fn into_bytes(mut self) -> Vec<u8> {
        if self.nbits != 0 {
            self.cur <<= 8 - self.nbits;
            self.bytes.push(self.cur);
            self.cur = 0;
            self.nbits = 0;
        }
        self.bytes
    }
}

// ---------------------------------------------------------------------------
// Sample-rate tables.
// ---------------------------------------------------------------------------

/// Standard MPEG-4 sampling-frequency table.
const SAMPLE_RATES: [u32; 13] = [
    96000, 88200, 64000, 48000, 44100, 32000, 24000, 22050, 16000, 12000, 11025, 8000, 7350,
];

/// Returns the samplingFrequencyIndex for `rate`, or `None` if unsupported.
pub fn sampling_frequency_index(rate: u32) -> Option<u8> {
    SAMPLE_RATES.iter().position(|&r| r == rate).map(|i| i as u8)
}

