/// Returns the long-window swb_offset table for a sampling-frequency index.
fn swb_offset_long(sfi: u8) -> &'static [u16] {
    match sfi {
        0 | 1 | 2 => SWB_LONG_96,
        3 | 4 => SWB_LONG_48,
        5 => SWB_LONG_32,
        6 | 7 => SWB_LONG_24,
        8 | 9 | 10 => SWB_LONG_16,
        11 | 12 => SWB_LONG_8,
        _ => SWB_LONG_48,
    }
}

// ---------------------------------------------------------------------------
// MDCT (forward, 2048 -> 1024) with KBD/sine window. We use the sine window.
// ---------------------------------------------------------------------------

/// Forward MDCT: N=2048 time samples -> 1024 spectral coefficients.
///
/// X[k] = sum_{n=0}^{2N-1} x[n] * cos( (pi/N) * (n + 1/2 + N/2) * (k + 1/2) ),
/// with N = 1024. Direct O(N^2) evaluation — fine for an offline-ish encoder and
/// keeps the code transparent. The 2048 input is the windowed overlap region.
fn mdct_1024(input: &[f64; 2048], out: &mut [f64; 1024]) {
    let n = 1024usize;
    let two_n = 2 * n;
    let n0 = (n as f64 / 2.0) + 0.5; // (N/2 + 1/2)
    let scale = core::f64::consts::PI / (n as f64);
    for k in 0..n {
        let kp = k as f64 + 0.5;
        let mut acc = 0.0f64;
        for m in 0..two_n {
            let angle = scale * (m as f64 + n0) * kp;
            acc += input[m] * angle.cos();
        }
        out[k] = acc;
    }
}

/// Sine analysis window of length 2N=2048.
fn sine_window(n2: usize) -> Vec<f64> {
    let mut w = Vec::with_capacity(n2);
    let nn = n2 as f64;
    for i in 0..n2 {
        let v = (core::f64::consts::PI / nn * (i as f64 + 0.5)).sin();
        w.push(v);
    }
    w
}

// ---------------------------------------------------------------------------
// AAC non-linear quantizer.
//
// Forward:  ix = sign(c) * floor( ( |c| * 2^(-1/4 * (sf - 100)) )^(3/4) + MAGIC )
// where MAGIC = 0.4054. We use the canonical AAC quant where the scalefactor
// "scf" raises the gain. Decoder inverse: c = sign(ix) * |ix|^(4/3) * 2^(0.25*(scf-100)).
// We expose a single global gain + per-band scalefactors (delta-coded with HCB-SF).
// ---------------------------------------------------------------------------

const SF_OFFSET: i32 = 100;
const QUANT_MAGIC: f64 = 0.4054;
/// AAC spectral magnitudes must satisfy |ix| <= 8191 (escape covers beyond 16).
const MAX_QUANT: i32 = 8191;

#[inline]
fn quantize_coeff(coeff: f64, scalefactor: i32) -> i32 {
    if coeff == 0.0 {
        return 0;
    }
    // Canonical AAC quantizer: ix = floor( (|c| * 2^(-(scf-100)/4))^(3/4) + MAGIC ).
    let exp = -0.25 * (scalefactor as f64 - SF_OFFSET as f64);
    let scaled = coeff.abs() * 2f64.powf(exp);
    let q = (scaled.powf(0.75) + QUANT_MAGIC).floor() as i32;
    let q = q.min(MAX_QUANT);
    if coeff < 0.0 { -q } else { q }
}

/// Decoder inverse of [`quantize_coeff`] — documents the round-trip; used by tests.
#[allow(dead_code)]
#[inline]
fn dequantize_coeff(ix: i32, scalefactor: i32) -> f64 {
    if ix == 0 {
        return 0.0;
    }
    let mag = (ix.abs() as f64).powf(4.0 / 3.0);
    let g = 2f64.powf(0.25 * (scalefactor as f64 - SF_OFFSET as f64));
    let v = mag * g;
    if ix < 0 { -v } else { v }
}

// ---------------------------------------------------------------------------
// AAC spectral Huffman codebooks.
//
// Codebooks 1..=11. Each codebook codes a tuple of either 4 (cb 1..=4) or 2
// (cb 5..=11) quantized values. We store, for each codeword index, the codeword
// length and the codeword bits. The index ordering follows the spec: for a
// 4-tuple unsigned-dimension codebook the index = ((w*M + x)*M + y)*M + z where
// M = 2*mod + 1 (signed) ... To keep this implementation tractable AND correct,
// we generate the codeword tables from the canonical Huffman code-length +
// codeword tables shipped in the AAC reference (ISO/IEC 13818-7 Annex / the
// well-known `huff_codebook` arrays). We embed them directly below.
//
// Representation: HCB[cb] is a slice of (len, code) pairs indexed by the tuple
// index. LAV (largest absolute value) and dimension drive index computation.
// ---------------------------------------------------------------------------

struct Codebook {
    dim: usize,        // 2 or 4
    lav: i32,          // largest absolute value (unsigned: range 0..=lav, signed: -lav..=lav)
    unsigned: bool,    // true => magnitudes coded, signs appended after
    /// (length, code) indexed by tuple index.
    table: &'static [(u8, u16)],
    /// For escape codebook (cb 11) only.
    escape: bool,
}

