static CODEBOOKS: [Codebook; 12] = [
    Codebook { dim: 0, lav: 0, unsigned: false, table: &HCB0_TABLE, escape: false }, // 0 ZERO_HCB
    Codebook { dim: 4, lav: 1, unsigned: false, table: &HCB1_TABLE, escape: false }, // 1
    Codebook { dim: 4, lav: 1, unsigned: false, table: &HCB2_TABLE, escape: false }, // 2
    Codebook { dim: 4, lav: 2, unsigned: true, table: &HCB3_TABLE, escape: false }, // 3
    Codebook { dim: 4, lav: 2, unsigned: true, table: &HCB4_TABLE, escape: false }, // 4
    Codebook { dim: 2, lav: 4, unsigned: false, table: &HCB5_TABLE, escape: false }, // 5
    Codebook { dim: 2, lav: 4, unsigned: false, table: &HCB6_TABLE, escape: false }, // 6
    Codebook { dim: 2, lav: 7, unsigned: true, table: &HCB7_TABLE, escape: false }, // 7
    Codebook { dim: 2, lav: 7, unsigned: true, table: &HCB8_TABLE, escape: false }, // 8
    Codebook { dim: 2, lav: 12, unsigned: true, table: &HCB9_TABLE, escape: false }, // 9
    Codebook { dim: 2, lav: 12, unsigned: true, table: &HCB10_TABLE, escape: false }, // 10
    Codebook { dim: 2, lav: 16, unsigned: true, table: &HCB11_TABLE, escape: true }, // 11
];


/// Compute the tuple index for a set of values under a codebook.
/// For signed codebooks the value range is [-lav, lav] mapped to [0, 2*lav].
/// For unsigned codebooks the magnitude range is [0, lav].
fn tuple_index(cb: &Codebook, vals: &[i32]) -> usize {
    let m = if cb.unsigned {
        (cb.lav + 1) as usize
    } else {
        (2 * cb.lav + 1) as usize
    };
    let mut idx = 0usize;
    for &v in vals.iter() {
        let comp = if cb.unsigned {
            v.unsigned_abs() as usize
        } else {
            (v + cb.lav) as usize
        };
        idx = idx * m + comp;
    }
    idx
}

/// Emit one codebook's coded representation of a tuple at writer position.
/// Returns the number of bits written.
fn write_tuple(bw: &mut BitWriter, cbnum: usize, vals: &[i32]) {
    let cb = &CODEBOOKS[cbnum];
    // Escape codebook 11 clamps magnitudes to 16 for the Huffman index; the true
    // magnitude (>=16) is appended as an escape sequence.
    if cb.escape {
        let mut clamped = [0i32; 2];
        for i in 0..2 {
            let a = vals[i].abs();
            clamped[i] = if a >= 16 { 16 } else { a };
        }
        let idx = tuple_index(cb, &clamped);
        let (len, code) = cb.table[idx];
        bw.put_bits(code as u32, len as u32);
        // signs (unsigned codebook): one sign bit per non-zero value, in order.
        for i in 0..2 {
            if vals[i] != 0 {
                bw.put_bit(if vals[i] < 0 { 1 } else { 0 });
            }
        }
        // escape for each value with |v| >= 16
        for i in 0..2 {
            let a = vals[i].unsigned_abs();
            if a >= 16 {
                // N = number of bits in a, minus 4; prefix = (N-... ) ones then a 0,
                // then the value in (escape_prefix) bits. Per spec:
                // escape_sequence = (n) '1' bits, a '0', then the (n+4)-bit binary of |value|.
                let n = (32 - a.leading_zeros()) as i32 - 4; // a has >=5 bits since a>=16
                let nbits = (n + 4) as u32;
                for _ in 0..n {
                    bw.put_bit(1);
                }
                bw.put_bit(0);
                bw.put_bits(a, nbits);
            }
        }
        return;
    }

    let idx = tuple_index(cb, vals);
    let (len, code) = cb.table[idx];
    bw.put_bits(code as u32, len as u32);
    if cb.unsigned {
        for &v in vals.iter() {
            if v != 0 {
                bw.put_bit(if v < 0 { 1 } else { 0 });
            }
        }
    }
}

/// Cost in bits of coding a tuple under a codebook (for codebook selection).
fn tuple_bits(cbnum: usize, vals: &[i32]) -> u32 {
    let cb = &CODEBOOKS[cbnum];
    if cb.escape {
        let mut clamped = [0i32; 2];
        let mut bits = 0u32;
        for i in 0..2 {
            let a = vals[i].abs();
            clamped[i] = if a >= 16 { 16 } else { a };
        }
        let idx = tuple_index(cb, &clamped);
        bits += cb.table[idx].0 as u32;
        for i in 0..2 {
            if vals[i] != 0 {
                bits += 1;
            }
        }
        for i in 0..2 {
            let a = vals[i].unsigned_abs();
            if a >= 16 {
                let n = (32 - a.leading_zeros()) as i32 - 4;
                bits += n as u32 + 1 + (n as u32 + 4);
            }
        }
        return bits;
    }
    let idx = tuple_index(cb, vals);
    let mut bits = cb.table[idx].0 as u32;
    if cb.unsigned {
        for &v in vals.iter() {
            if v != 0 {
                bits += 1;
            }
        }
    }
    bits
}

/// Maximum absolute value codeable per codebook (for picking a legal cb).
fn cb_lav(cbnum: usize) -> i32 {
    CODEBOOKS[cbnum].lav
}
fn cb_dim(cbnum: usize) -> usize {
    CODEBOOKS[cbnum].dim
}

/// Pick the cheapest legal codebook for a contiguous spectral section [start,end)
/// of quantized coefficients. Returns (cbnum, total_bits). We consider a useful
/// subset: 0 (all-zero), 1..=11.
fn choose_codebook(quant: &[i32], start: usize, end: usize) -> (usize, u32) {
    // All zero?
    if quant[start..end].iter().all(|&q| q == 0) {
        return (0, 0);
    }
    let maxabs = quant[start..end].iter().map(|&q| q.abs()).max().unwrap_or(0);
    let mut best: Option<(usize, u32)> = None;
    for cbnum in 1..=11usize {
        let lav = cb_lav(cbnum);
        // cb 11 is escape: lav effectively unbounded (16+escape).
        if cbnum != 11 && maxabs > lav {
            continue;
        }
        let dim = cb_dim(cbnum);
        let mut bits = 0u32;
        let mut i = start;
        while i < end {
            if dim == 4 {
                let v = [quant[i], quant[i + 1], quant[i + 2], quant[i + 3]];
                bits += tuple_bits(cbnum, &v);
                i += 4;
            } else {
                let v = [quant[i], quant[i + 1]];
                bits += tuple_bits(cbnum, &v);
                i += 2;
            }
        }
        match best {
            None => best = Some((cbnum, bits)),
            Some((_, b)) if bits < b => best = Some((cbnum, bits)),
            _ => {}
        }
    }
    best.unwrap_or((11, 0))
}

