#[cfg(test)]
mod tests {
    use super::*;

    fn ffmpeg_ok() -> bool {
        std::process::Command::new("ffmpeg")
            .arg("-version")
            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .status()
            .map(|s| s.success())
            .unwrap_or(false)
    }
    fn ffprobe_ok() -> bool {
        std::process::Command::new("ffprobe")
            .arg("-version")
            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .status()
            .map(|s| s.success())
            .unwrap_or(false)
    }

    #[test]
    fn asc_silence_mono_44100() {
        // Pure-Rust structural checks (always run).
        let pcm = vec![0i16; 44100 / 4]; // 0.25s mono
        let enc = encode_aac_lc(&pcm, 44100, 1);
        assert_eq!(enc.sampling_frequency_index, 4, "44100 => sfi 4");
        assert_eq!(enc.channel_configuration, 1);
        // ASC for AAC-LC mono 44100 = 00010 0100 0001 000 => 0x12 0x08.
        assert_eq!(enc.asc, vec![0x12, 0x08], "ASC bytes mismatch: {:02X?}", enc.asc);
        assert!(!enc.frames.is_empty());
        // every frame ends byte-aligned with content
        for fr in &enc.frames {
            assert!(!fr.is_empty());
        }
    }

    #[test]
    fn rung1_silence_decodes() {
        if !ffmpeg_ok() || !ffprobe_ok() {
            eprintln!("[aac] ffmpeg/ffprobe absent — skipping rung 1");
            return;
        }
        let pcm = vec![0i16; 44100 / 4]; // 0.25s of silence, mono
        let stream = encode_to_adts_stream(&pcm, 44100, 1);
        let p = std::env::temp_dir().join("aac_silence.aac");
        std::fs::write(&p, &stream).expect("write silence aac");

        // ffprobe: codec_name=aac, sample_rate=44100, channels=1
        let probe = std::process::Command::new("ffprobe")
            .args([
                "-v", "error", "-select_streams", "a:0", "-show_entries",
                "stream=codec_name,sample_rate,channels", "-of", "default=noprint_wrappers=1",
            ])
            .arg(&p)
            .output()
            .expect("run ffprobe");
        let txt = String::from_utf8_lossy(&probe.stdout);
        eprintln!("[aac rung1] ffprobe:\n{}", txt);
        assert!(probe.status.success(), "ffprobe failed: {}", String::from_utf8_lossy(&probe.stderr));
        assert!(txt.contains("codec_name=aac"), "not aac: {}", txt);
        assert!(txt.contains("sample_rate=44100"), "wrong rate: {}", txt);
        assert!(txt.contains("channels=1"), "wrong channels: {}", txt);

        // ffmpeg full decode, no errors
        let dec = std::process::Command::new("ffmpeg")
            .args(["-v", "error", "-i"])
            .arg(&p)
            .args(["-f", "null", "-"])
            .output()
            .expect("run ffmpeg decode");
        let err = String::from_utf8_lossy(&dec.stderr);
        assert!(dec.status.success(), "ffmpeg decode failed: {}", err);
        assert!(err.is_empty(), "ffmpeg reported decode errors: {}", err);
        eprintln!("[aac rung1] silence decoded cleanly ({} bytes stream)", stream.len());
    }

    #[test]
    fn rung2_sine_440_decodes() {
        if !ffmpeg_ok() {
            eprintln!("[aac] ffmpeg absent — skipping rung 2");
            return;
        }
        let sr = 44100u32;
        let n = (sr / 2) as usize; // 0.5s
        let mut pcm = Vec::with_capacity(n);
        for i in 0..n {
            let t = i as f64 / sr as f64;
            let s = (2.0 * core::f64::consts::PI * 440.0 * t).sin() * 0.5;
            pcm.push((s * 32767.0) as i16);
        }
        let stream = encode_to_adts_stream(&pcm, sr, 1);
        let p = std::env::temp_dir().join("aac_sine440.aac");
        std::fs::write(&p, &stream).expect("write sine aac");

        let dec = std::process::Command::new("ffmpeg")
            .args(["-v", "error", "-i"])
            .arg(&p)
            .args(["-f", "s16le", "-ac", "1", "-ar", "44100", "-"])
            .output()
            .expect("run ffmpeg decode to pcm");
        let err = String::from_utf8_lossy(&dec.stderr);
        assert!(dec.status.success(), "ffmpeg sine decode failed: {}", err);
        // Decoded PCM
        let raw = dec.stdout;
        assert!(!raw.is_empty(), "decoded PCM empty");
        let mut samples: Vec<f64> = Vec::with_capacity(raw.len() / 2);
        for ch in raw.chunks_exact(2) {
            let v = i16::from_le_bytes([ch[0], ch[1]]) as f64;
            samples.push(v);
        }
        // Non-silence check
        let energy: f64 = samples.iter().map(|x| x * x).sum::<f64>() / samples.len() as f64;
        eprintln!("[aac rung2] decoded {} samples, rms={:.1}", samples.len(), energy.sqrt());
        assert!(energy.sqrt() > 50.0, "decoded signal is ~silent (rms={:.2})", energy.sqrt());

        // Dominant frequency via zero-crossing rate (skip the initial overlap ramp).
        let skip = 2048.min(samples.len() / 4);
        let active = &samples[skip..];
        let mut crossings = 0usize;
        for w in active.windows(2) {
            if (w[0] <= 0.0 && w[1] > 0.0) || (w[0] >= 0.0 && w[1] < 0.0) {
                crossings += 1;
            }
        }
        let dur = active.len() as f64 / sr as f64;
        let est_freq = (crossings as f64 / 2.0) / dur;
        eprintln!("[aac rung2] zero-crossing dominant freq ~= {:.1} Hz (expect ~440)", est_freq);
        assert!(
            est_freq > 350.0 && est_freq < 530.0,
            "dominant frequency {:.1}Hz not near 440Hz",
            est_freq
        );
    }

    #[test]
    fn rung3_stereo_48000() {
        if !ffmpeg_ok() || !ffprobe_ok() {
            eprintln!("[aac] ffmpeg/ffprobe absent — skipping rung 3");
            return;
        }
        let sr = 48000u32;
        let n = (sr / 4) as usize; // 0.25s per channel
        let mut pcm = Vec::with_capacity(n * 2);
        for i in 0..n {
            let t = i as f64 / sr as f64;
            let l = (2.0 * core::f64::consts::PI * 440.0 * t).sin() * 0.4;
            let r = (2.0 * core::f64::consts::PI * 660.0 * t).sin() * 0.4;
            pcm.push((l * 32767.0) as i16);
            pcm.push((r * 32767.0) as i16);
        }
        let stream = encode_to_adts_stream(&pcm, sr, 2);
        let p = std::env::temp_dir().join("aac_stereo48k.aac");
        std::fs::write(&p, &stream).expect("write stereo aac");

        let probe = std::process::Command::new("ffprobe")
            .args([
                "-v", "error", "-select_streams", "a:0", "-show_entries",
                "stream=codec_name,sample_rate,channels", "-of", "default=noprint_wrappers=1",
            ])
            .arg(&p)
            .output()
            .expect("run ffprobe");
        let txt = String::from_utf8_lossy(&probe.stdout);
        eprintln!("[aac rung3] ffprobe:\n{}", txt);
        assert!(txt.contains("codec_name=aac"), "not aac: {}", txt);
        assert!(txt.contains("sample_rate=48000"), "wrong rate: {}", txt);
        assert!(txt.contains("channels=2"), "wrong channels: {}", txt);

        let dec = std::process::Command::new("ffmpeg")
            .args(["-v", "error", "-i"])
            .arg(&p)
            .args(["-f", "null", "-"])
            .output()
            .expect("run ffmpeg decode");
        let err = String::from_utf8_lossy(&dec.stderr);
        assert!(dec.status.success(), "stereo decode failed: {}", err);
        assert!(err.is_empty(), "stereo decode errors: {}", err);
        eprintln!("[aac rung3] stereo 48k decoded cleanly");
    }
}
